-- Convert the 12 "Intensive Listening Intermediate N" lessons (N = 2..13) in
-- "The Canto to Mando Blueprint - Intermediate" from Audio to Listening
-- Practice, keeping their titles and loading the Mandarin sentences from the
-- Intensive Listening doc. Pinyin = the doc's (typos corrected, cleaned to one
-- syllable per character); English = translations; audio = per-sentence TTS
-- (audioUrl null). Lesson 1 is intentionally not included (already done).
--
-- Idempotent + tightly scoped: only lessons still typed 'audio', titled
-- "Intensive Listening…", in that course, matched to their content by the
-- number in the title. Re-running is a no-op.

UPDATE "course_library_lessons" AS l
SET "lesson_type" = 'listening_practice',
    "content" = v.content,
    "updated_at" = now()
FROM (VALUES
  (2, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"8aa85af4-3467-4d99-be92-ef27aa12da08","order":0,"chinese":"你走得这么快!","pinyin":"nǐ zǒu de zhè me kuài","english":"You walk so fast!","audioUrl":null},{"id":"0c0eb907-6bac-441b-8c02-69484a821317","order":1,"chinese":"你们吃得那么慢","pinyin":"nǐ men chī de nà me màn","english":"You guys eat so slowly","audioUrl":null},{"id":"1683ba05-d2ef-4ef4-bded-47a5806767e3","order":2,"chinese":"我在飞机上睡得这么差","pinyin":"wǒ zài fēi jī shàng shuì de zhè me chà","english":"I slept so badly on the plane","audioUrl":null},{"id":"984af4d7-67b3-494c-a0ef-c7b520feccf9","order":3,"chinese":"我不知道海里面会有那么多鱼","pinyin":"wǒ bù zhī dào hǎi lǐ miàn huì yǒu nà me duō yú","english":"I didn''t know there would be so many fish in the sea","audioUrl":null},{"id":"5e2288b3-7676-43db-a0c4-0b090dbda203","order":4,"chinese":"如果你继续这样追她, 她会不喜欢你","pinyin":"rú guǒ nǐ jì xù zhè yàng zhuī tā tā huì bù xǐ huan nǐ","english":"If you keep chasing her like this, she won''t like you","audioUrl":null},{"id":"8af24966-72bc-4955-a783-b78a168b1f9d","order":5,"chinese":"你要继续这样做","pinyin":"nǐ yào jì xù zhè yàng zuò","english":"You have to keep doing it like this","audioUrl":null},{"id":"39dd0911-27b0-4c22-84a8-1a7336477aec","order":6,"chinese":"你觉得这样做很好吗？","pinyin":"nǐ jué de zhè yàng zuò hěn hǎo ma","english":"Do you think doing it this way is good?","audioUrl":null},{"id":"ac732ca3-ecbd-4c40-b724-1789ff8043e4","order":7,"chinese":"就算是这样, 我会继续喜欢她","pinyin":"jiù suàn shì zhè yàng wǒ huì jì xù xǐ huan tā","english":"Even so, I''ll keep liking her","audioUrl":null},{"id":"ec67d09c-b1fe-458c-8a2a-e76aa36c2fef","order":8,"chinese":"那你今晚想做什么?","pinyin":"nà nǐ jīn wǎn xiǎng zuò shén me","english":"So what do you want to do tonight?","audioUrl":null},{"id":"095037c0-8683-46ca-9c7f-9afe83ada39e","order":9,"chinese":"那如果你喜欢她, 你要去追她","pinyin":"nà rú guǒ nǐ xǐ huan tā nǐ yào qù zhuī tā","english":"Well, if you like her, you should go after her","audioUrl":null},{"id":"29ddde85-67d8-417c-80a6-66e5c1de1e61","order":10,"chinese":"那我们要去追那个明星","pinyin":"nà wǒ men yào qù zhuī nà ge míng xīng","english":"Then we should go chase that celebrity","audioUrl":null},{"id":"571b49da-b732-4ac0-88e7-2b3b3452b238","order":11,"chinese":"那你跑步要跑得快一点","pinyin":"nà nǐ pǎo bù yào pǎo de kuài yì diǎn","english":"Then you need to run a bit faster","audioUrl":null},{"id":"45b2414c-f427-4d5a-a6bf-10f817ec3630","order":12,"chinese":"我可以说一点中文","pinyin":"wǒ kě yǐ shuō yì diǎn zhōng wén","english":"I can speak a little Chinese","audioUrl":null},{"id":"78458b9e-ba3b-4889-93fb-893857890ca2","order":13,"chinese":"给我多点水","pinyin":"gěi wǒ duō diǎn shuǐ","english":"Give me more water","audioUrl":null},{"id":"9fd806c0-3520-47fc-a91c-75efa5c1cfa0","order":14,"chinese":"可以多加一点吗","pinyin":"kě yǐ duō jiā yì diǎn ma","english":"Can you add a little more?","audioUrl":null},{"id":"138225ae-3ccc-4df4-9aa2-46d364c33fea","order":15,"chinese":"那你这样说是对的","pinyin":"nà nǐ zhè yàng shuō shì duì de","english":"Then what you''re saying is right","audioUrl":null},{"id":"f3f705fe-c8ae-48d8-aa34-fbbe705c3e7c","order":16,"chinese":"那么高! 请介绍一下你的朋友!","pinyin":"nà me gāo qǐng jiè shào yí xià nǐ de péng you","english":"So tall! Please introduce your friend!","audioUrl":null},{"id":"b9479f96-145f-4335-a973-ebd01b2011bc","order":17,"chinese":"要做那么多功课? 我哪里有时间","pinyin":"yào zuò nà me duō gōng kè wǒ nǎ lǐ yǒu shí jiān","english":"So much homework to do? Where would I find the time?","audioUrl":null}]}'::jsonb),
  (3, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"88f059b3-7e0f-49f7-9405-07a4b63a5053","order":0,"chinese":"千万不要坐在中间位置","pinyin":"qiān wàn bú yào zuò zài zhōng jiān wèi zhi","english":"Whatever you do, don''t sit in the middle seat","audioUrl":null},{"id":"0d3c81d9-60fb-4e84-99c8-d4df4b50fc14","order":1,"chinese":"注意安全！千万别解开你的安全带","pinyin":"zhù yì ān quán qiān wàn bié jiě kāi nǐ de ān quán dài","english":"Stay safe! Whatever you do, don''t unfasten your seatbelt","audioUrl":null},{"id":"053cfcc6-3ae5-40ac-a88d-8afc0058ae0e","order":2,"chinese":"千万不要和不愿意公开关系的男人谈恋爱","pinyin":"qiān wàn bú yào hé bú yuàn yì gōng kāi guān xi de nán rén tán liàn ài","english":"Never date a man who isn''t willing to make the relationship public","audioUrl":null},{"id":"bae112ee-7b35-4b8a-91b8-839d87eb0d0e","order":3,"chinese":"不用袋子了! 谢谢!","pinyin":"bú yòng dài zi le xiè xiè","english":"No bag needed! Thanks!","audioUrl":null},{"id":"62152bbc-a13b-43ee-856c-7db2e3fa58b4","order":4,"chinese":"老师说明天不用上学","pinyin":"lǎo shī shuō míng tiān bú yòng shàng xué","english":"The teacher said we don''t have to go to school tomorrow","audioUrl":null},{"id":"dab5efb5-5b4d-4db5-baa6-f9af0e280420","order":5,"chinese":"进来的时候不用脱鞋子","pinyin":"jìn lái de shí hòu bú yòng tuō xié zi","english":"You don''t need to take off your shoes when you come in","audioUrl":null},{"id":"c84cd1a0-b308-4740-ac89-15911e181af3","order":6,"chinese":"你为什么要在我面前脱衣服","pinyin":"nǐ wèi shén me yào zài wǒ miàn qián tuō yī fu","english":"Why are you taking off your clothes in front of me?","audioUrl":null},{"id":"6d64700b-c671-4bd6-9a22-b6bffeb69dc9","order":7,"chinese":"你进来就要脱鞋子","pinyin":"nǐ jìn lái jiù yào tuō xié zi","english":"You have to take off your shoes when you come in","audioUrl":null},{"id":"cb2a85d7-b4f9-44c1-b747-2a846660696f","order":8,"chinese":"女人说 “不用麻烦你” 是什么意思","pinyin":"nǚ rén shuō bú yòng má fan nǐ shì shén me yì si","english":"What does it mean when a woman says “don''t trouble yourself”?","audioUrl":null},{"id":"ce82cbbe-8ac9-4f44-989e-ff5b139b78fa","order":9,"chinese":"请大家不要在这里抽烟","pinyin":"qǐng dà jiā bú yào zài zhè lǐ chōu yān","english":"Everyone, please don''t smoke here","audioUrl":null},{"id":"544d548e-0e4e-4bf7-8392-6b5485f7d767","order":10,"chinese":"别这样想","pinyin":"bié zhè yàng xiǎng","english":"Don''t think like that","audioUrl":null}]}'::jsonb),
  (4, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"5f57a7e1-a816-4957-96fe-7a9d8edf73f4","order":0,"chinese":"我今年已经花了很多钱","pinyin":"wǒ jīn nián yǐ jīng huā le hěn duō qián","english":"I''ve already spent a lot of money this year","audioUrl":null},{"id":"5abec5cb-075b-43ac-a2bd-7fe14ba6c600","order":1,"chinese":"全世界会来这个广场花钱","pinyin":"quán shì jiè huì lái zhè ge guǎng chǎng huā qián","english":"People from all over the world come to this square to spend money","audioUrl":null},{"id":"d1d4dec7-bd47-4cb9-912e-73340760cf5e","order":2,"chinese":"我已经发了那个电子邮件给你了","pinyin":"wǒ yǐ jīng fā le nà ge diàn zǐ yóu jiàn gěi nǐ le","english":"I''ve already sent you that email","audioUrl":null},{"id":"ac9b6f2d-3227-4780-948c-ecbef079e8fd","order":3,"chinese":"他已经到了能够决定的年纪了","pinyin":"tā yǐ jīng dào le néng gòu jué dìng de nián jì le","english":"He''s already old enough to make his own decisions","audioUrl":null},{"id":"3be1e1d9-1e9a-4bbf-b7b1-0808a46f270b","order":4,"chinese":"好奇怪... 每一扇门都开不了","pinyin":"hǎo qí guài měi yí shàn mén dōu kāi bù liǎo","english":"How strange... none of the doors will open","audioUrl":null},{"id":"d2a5755e-606b-4be4-9a9b-d5f1ec1be74d","order":5,"chinese":"我开不了抢, 你没有装子弹","pinyin":"wǒ kāi bù liǎo qiāng nǐ méi yǒu zhuāng zǐ dàn","english":"I can''t fire the gun, you didn''t load the bullets","audioUrl":null},{"id":"a5e8158d-960a-4e3e-8d4e-ce93592f07a7","order":6,"chinese":"第一个原因是因为你肯定做不了","pinyin":"dì yī gè yuán yīn shì yīn wèi nǐ kěn dìng zuò bù liǎo","english":"The first reason is that you definitely won''t be able to do it","audioUrl":null},{"id":"c18e49e2-8152-40ee-83ca-1ed0bda625bc","order":7,"chinese":"谢谢你的热情服务! 但是我吃不了了!","pinyin":"xiè xiè nǐ de rè qíng fú wù dàn shì wǒ chī bù liǎo le","english":"Thank you for the warm service! But I can''t eat any more!","audioUrl":null},{"id":"0cb16f9b-f553-42fd-bb2b-ac8a3d2316eb","order":8,"chinese":"之后的事我就控制不了了!","pinyin":"zhī hòu de shì wǒ jiù kòng zhì bù liǎo le","english":"After that, it''ll be out of my control!","audioUrl":null},{"id":"ecfd2d5f-6283-4709-859b-f3dfce6ca625","order":9,"chinese":"而且, 我们现在改不了了","pinyin":"ér qiě wǒ men xiàn zài gǎi bù liǎo le","english":"Besides, we can''t change it now","audioUrl":null},{"id":"bfe619b8-95b8-431d-b6db-420968cd521f","order":10,"chinese":"但是下次你别再试了","pinyin":"dàn shì xià cì nǐ bié zài shì le","english":"But don''t try again next time","audioUrl":null},{"id":"fca2c272-3257-49f9-acea-b8321cf21754","order":11,"chinese":"不要再问关于他的问题了","pinyin":"bú yào zài wèn guān yú tā de wèn tí le","english":"Don''t ask any more questions about him","audioUrl":null},{"id":"4a51dfd1-c7da-4c8f-bf25-eec45bec2f3d","order":12,"chinese":"我的雨伞关不了了","pinyin":"wǒ de yǔ sǎn guān bù liǎo le","english":"My umbrella won''t close anymore","audioUrl":null}]}'::jsonb),
  (5, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"2d607a0e-595d-41c3-9b7f-1925234024a1","order":0,"chinese":"他们说我们爱男人只为了 钱","pinyin":"tā men shuō wǒ men ài nán rén zhǐ wèi le qián","english":"They say we only love men for money","audioUrl":null},{"id":"1d8c0f3a-2cd3-4138-b174-b2dac8c068f7","order":1,"chinese":"为了赚钱, 你就离开了我","pinyin":"wèi le zhuàn qián nǐ jiù lí kāi le wǒ","english":"You left me just to make money","audioUrl":null},{"id":"3adffcda-d9b9-493a-a30f-9b131d9fb668","order":2,"chinese":"你天天去见他, 是为了什么","pinyin":"nǐ tiān tiān qù jiàn tā shì wèi le shén me","english":"You go see him every day — what for?","audioUrl":null},{"id":"8f7840c5-81f8-437c-8e8b-b6d8ea5ec803","order":3,"chinese":"原因是为了给你我的旧照相机","pinyin":"yuán yīn shì wèi le gěi nǐ wǒ de jiù zhào xiàng jī","english":"The reason is to give you my old camera","audioUrl":null},{"id":"d9d5f5d0-50b0-48cc-9e6d-40039a9dc4d0","order":4,"chinese":"为了帮他拍照, 我经常要去街道","pinyin":"wèi le bāng tā pāi zhào wǒ jīng cháng yào qù jiē dào","english":"To take photos for him, I often have to go out to the streets","audioUrl":null},{"id":"d2650dc1-6adb-4d10-9cff-5afa544bafde","order":5,"chinese":"只有你还没吃完饭","pinyin":"zhǐ yǒu nǐ hái méi chī wán fàn","english":"You''re the only one who hasn''t finished eating","audioUrl":null},{"id":"337948ec-e4c9-4d43-82c8-63e15652986d","order":6,"chinese":"只有这袋米有那个奇怪的味道","pinyin":"zhǐ yǒu zhè dài mǐ yǒu nà ge qí guài de wèi dao","english":"Only this bag of rice has that strange smell","audioUrl":null},{"id":"54cec90b-5144-419e-a88f-0afabedf937a","order":7,"chinese":"今天好像只有那间餐厅开门","pinyin":"jīn tiān hǎo xiàng zhǐ yǒu nà jiān cān tīng kāi mén","english":"It seems only that restaurant is open today","audioUrl":null},{"id":"79145d09-577b-4492-8567-e2f11d1dd1ca","order":8,"chinese":"现在北京的天气好像很热","pinyin":"xiàn zài běi jīng de tiān qì hǎo xiàng hěn rè","english":"The weather in Beijing seems really hot right now","audioUrl":null},{"id":"6908858b-6b8d-42ad-9d3b-dd243482b172","order":9,"chinese":"原来机票的价钱是一千块钱","pinyin":"yuán lái jī piào de jià qian shì yì qiān kuài qián","english":"It turns out the plane ticket costs a thousand dollars","audioUrl":null},{"id":"6ed98624-6cf1-42ad-8bb8-63b9c90bc827","order":10,"chinese":"我家附近的超市很贵! 要带几百块钱!","pinyin":"wǒ jiā fù jìn de chāo shì hěn guì yào dài jǐ bǎi kuài qián","english":"The supermarket near my home is expensive — you need to bring a few hundred dollars!","audioUrl":null},{"id":"3b6219c6-e36b-49c8-90ca-fef4052965b0","order":11,"chinese":"小姐, 好像只有你还没选好","pinyin":"xiǎo jie hǎo xiàng zhǐ yǒu nǐ hái méi xuǎn hǎo","english":"Miss, it seems you''re the only one who hasn''t decided yet","audioUrl":null}]}'::jsonb),
  (6, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"1b929c00-e17a-44b2-87e7-913a16356496","order":0,"chinese":"我妈妈也不是很开心","pinyin":"wǒ mā ma yě bú shì hěn kāi xīn","english":"My mom isn''t very happy either","audioUrl":null},{"id":"e151bb9c-eb89-414d-a2a8-cf8fc6a0c5ad","order":1,"chinese":"你也没有兴趣上班吗","pinyin":"nǐ yě méi yǒu xìng qù shàng bān ma","english":"Are you also not interested in going to work?","audioUrl":null},{"id":"d0d0bfeb-cc9b-433e-9b44-2e45dd8fcaf5","order":2,"chinese":"你们也觉得我的男朋友很无聊吗","pinyin":"nǐ men yě jué de wǒ de nán péng you hěn wú liáo ma","english":"Do you guys also think my boyfriend is boring?","audioUrl":null},{"id":"53fda7e3-f0a4-49dd-b967-c81d6fd8ce01","order":3,"chinese":"我觉得和他出去很无聊","pinyin":"wǒ jué de hé tā chū qù hěn wú liáo","english":"I think going out with him is boring","audioUrl":null},{"id":"2b87321b-f384-4e72-91c2-74644f145894","order":4,"chinese":"我觉得上学很无聊","pinyin":"wǒ jué de shàng xué hěn wú liáo","english":"I think going to school is boring","audioUrl":null},{"id":"2bfc91ad-b837-4886-9e27-26416f3bf649","order":5,"chinese":"我什么都想要","pinyin":"wǒ shén me dōu xiǎng yào","english":"I want everything","audioUrl":null},{"id":"ed9e9bdf-7b15-45e0-a602-d94d46d18c0d","order":6,"chinese":"我觉得全部问题都很难","pinyin":"wǒ jué de quán bù wèn tí dōu hěn nán","english":"I think all the questions are hard","audioUrl":null},{"id":"ce03326d-30a6-49a0-a48a-ba65812e6220","order":7,"chinese":"你所有答案都对","pinyin":"nǐ suǒ yǒu dá àn dōu duì","english":"All your answers are correct","audioUrl":null},{"id":"3532339f-7acb-43ea-882e-94f04094c757","order":8,"chinese":"我觉得今天考试所有问题都很容易","pinyin":"wǒ jué de jīn tiān kǎo shì suǒ yǒu wèn tí dōu hěn róng yì","english":"I think all the questions on today''s exam were easy","audioUrl":null},{"id":"3df20d5f-1b85-4015-a82c-1cd92ed66074","order":9,"chinese":"任何人都会这样想","pinyin":"rèn hé rén dōu huì zhè yàng xiǎng","english":"Anyone would think this way","audioUrl":null},{"id":"781fed91-1755-4cb0-a4fd-18764c685225","order":10,"chinese":"你选任何颜色都可以","pinyin":"nǐ xuǎn rèn hé yán sè dōu kě jǐ","english":"You can pick any color you like","audioUrl":null},{"id":"dce7be97-44ba-4c0c-819e-4dbb6bec98b6","order":11,"chinese":"我也觉得上学很容易很无聊","pinyin":"wǒ yě jué de shàng xué hěn róng yì hěn wú liáo","english":"I also think school is easy and boring","audioUrl":null},{"id":"0e1ab502-f90b-41d4-83d5-077d6faa30fa","order":12,"chinese":"任何人都会有兴趣看书","pinyin":"rèn hé rén dōu huì yǒu xìng qù kàn shū","english":"Anyone would be interested in reading","audioUrl":null},{"id":"88f6a8d7-f56b-45e6-bdb7-880ad3da34fc","order":13,"chinese":"我也觉得这个很难选","pinyin":"wǒ yě jué de zhè ge hěn nán xuǎn","english":"I also think this is hard to choose","audioUrl":null}]}'::jsonb),
  (7, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"42d4fa37-c44b-4f42-8329-a8cc3d3b96dd","order":0,"chinese":"我们在银行已经过了三个小时","pinyin":"wǒ men zài yín háng yǐ jīng guò le sān gè xiǎo shí","english":"We''ve already spent three hours at the bank","audioUrl":null},{"id":"8b75b742-ad0e-4159-a82a-cef30b70bbbd","order":1,"chinese":"二十五个小时之后, 你终于到了","pinyin":"èr shí wǔ gè xiǎo shí zhī hòu nǐ zhōng yú dào le","english":"After twenty-five hours, you finally arrived","audioUrl":null},{"id":"63222f23-a519-4c43-a43d-de13dc6ec6e0","order":2,"chinese":"六个小时之后, 你要记得煮饭","pinyin":"liù gè xiǎo shí zhī hòu nǐ yào jì de zhǔ fàn","english":"Six hours from now, remember to cook","audioUrl":null},{"id":"df862367-7b86-431d-83d7-b1fdfcba4368","order":3,"chinese":"这个礼物是她刚刚送给我的","pinyin":"zhè ge lǐ wù shì tā gāng gang sòng gěi wǒ de","english":"She just gave me this gift","audioUrl":null},{"id":"a39da27f-3935-4756-98f6-5b0a91214003","order":4,"chinese":"我真的不喜欢喝咖啡","pinyin":"wǒ zhēn de bù xǐ huan hē kā fēi","english":"I really don''t like drinking coffee","audioUrl":null},{"id":"4dc11c1e-7d53-42fc-a726-b9972e6dfbd5","order":5,"chinese":"吃饭之前要先去洗手间洗手","pinyin":"chī fàn zhī qián yào xiān qù xǐ shǒu jiān xǐ shǒu","english":"Before eating, go to the bathroom and wash your hands first","audioUrl":null},{"id":"69ba98be-ced1-4413-acf8-a1c8a7b091a2","order":6,"chinese":"请你先考完试再说","pinyin":"qǐng nǐ xiān kǎo wán shì zài shuō","english":"Finish your exam first, then we''ll talk","audioUrl":null},{"id":"d6dab1d5-1f9b-4d27-b3b4-0678d731e678","order":7,"chinese":"我喜欢先读完书再睡觉","pinyin":"wǒ xǐ huān xiān dú wán shū zài shuì jiào","english":"I like to finish reading before going to sleep","audioUrl":null},{"id":"9027a26a-dd9a-4b1d-b0d0-e7b7073658b4","order":8,"chinese":"你要在地铁站等一会","pinyin":"nǐ yào zài dì tiě zhàn děng yí huì","english":"You''ll have to wait a while at the subway station","audioUrl":null},{"id":"ceedf553-b001-4a4c-8c6c-4747bb85d82b","order":9,"chinese":"我很忙! 你可以等一会吗？","pinyin":"wǒ hěn máng nǐ kě yǐ děng yí huì ma","english":"I''m very busy! Can you wait a moment?","audioUrl":null},{"id":"ed8168df-1435-4d20-a814-2bc5177f3d1e","order":10,"chinese":"累死我了. 我要休息一会","pinyin":"lèi sǐ wǒ le wǒ yào xiū xi yí huì","english":"I''m exhausted. I need to rest for a bit","audioUrl":null},{"id":"838d7983-5501-4798-90eb-5797f3f74565","order":11,"chinese":"我今天真的超级累","pinyin":"wǒ jīn tiān zhēn de chāo jí lèi","english":"I''m really super tired today","audioUrl":null},{"id":"00c445bd-32ac-4c64-8ba9-cc4d48682ea0","order":12,"chinese":"你现在很累吗","pinyin":"nǐ xiàn zài hěn lèi ma","english":"Are you very tired right now?","audioUrl":null},{"id":"3076d08f-948c-4cf0-a802-9fc4f60843fc","order":13,"chinese":"当船进来的时候, 我会放心","pinyin":"dāng chuán jìn lái de shí hòu wǒ huì fàng xīn","english":"When the boat comes in, I''ll feel relieved","audioUrl":null},{"id":"bdd6fc72-9a50-466d-b0ce-d782f118d86f","order":14,"chinese":"为什么当我需要帮助的时候, 你们都不在？","pinyin":"wèi shén me dāng wǒ xū yào bāng zhù de shí hòu nǐ men dōu bú zài","english":"Why is it that when I need help, none of you are around?","audioUrl":null},{"id":"6ab0ad58-6425-49a6-9f68-8c16550cec93","order":15,"chinese":"医生已经等了几个小时...","pinyin":"yī shēng yǐ jīng děng le jǐ ge xiǎo shí","english":"The doctor has already been waiting for hours...","audioUrl":null},{"id":"41ae9229-c25f-4c4d-bbe3-0dc72d95cf5e","order":16,"chinese":"我刚刚上了出租车! 一会就到了","pinyin":"wǒ gāng gang shàng le chū zū chē yí huì jiù dào le","english":"I just got in a taxi! I''ll be there in a bit","audioUrl":null},{"id":"c1162834-5182-483a-a3b8-94a88fc65c5d","order":17,"chinese":"外面很冷, 你可以先关门吗","pinyin":"wài miàn hěn lěng nǐ kě yǐ xiān guān mén ma","english":"It''s cold outside — can you close the door first?","audioUrl":null},{"id":"bb4a6e80-c940-41aa-94b7-644238d1d2c3","order":18,"chinese":"外面很冷, 你可不可以先关门","pinyin":"wài miàn hěn lěng nǐ kě bù kě yǐ xiān guān mén","english":"It''s cold outside — could you close the door first?","audioUrl":null}]}'::jsonb),
  (8, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"81461791-5324-49f9-ae5b-b8cc6f8b34ab","order":0,"chinese":"不用等我! 你先上公共汽车吧","pinyin":"bú yòng děng wǒ nǐ xiān shàng gōng gòng qì chē ba","english":"Don''t wait for me! Go ahead and get on the bus","audioUrl":null},{"id":"ae66c65c-0d65-44f1-8ea8-92ea51d1f790","order":1,"chinese":"你一点汤都不要吗? 喝一点吧","pinyin":"nǐ yì diǎn tāng dōu bú yào ma hē yì diǎn ba","english":"You don''t want any soup at all? Have a little","audioUrl":null},{"id":"2b001c05-d73f-4f00-8203-4b6b13a66b3a","order":2,"chinese":"北方很热! 你快点回来吧!","pinyin":"běi fāng hěn rè nǐ kuài diǎn huí lái ba","english":"The north is really hot! Hurry back!","audioUrl":null},{"id":"68d7dbb8-6608-4554-a742-ccd900b90737","order":3,"chinese":"其他医院会有更多病人吧","pinyin":"qí tā yī yuàn huì yǒu gèng duō bìng rén ba","english":"Other hospitals probably have more patients","audioUrl":null},{"id":"3ce56e41-0382-4e7a-aedc-35a2f2e2c201","order":4,"chinese":"这个办法更好","pinyin":"zhè ge bàn fǎ gèng hǎo","english":"This method is better","audioUrl":null},{"id":"370bae36-8684-4304-8f27-ac3a2f50a995","order":5,"chinese":"请你给我一杯冰水吧","pinyin":"qǐng nǐ gěi wǒ yì bēi bīng shuǐ ba","english":"Please give me a glass of ice water","audioUrl":null},{"id":"827b9495-1a3a-4fb0-b53e-ae0d0793f17b","order":6,"chinese":"穿衣服吧! 我们一起出去吧","pinyin":"chuān yī fu ba wǒ men yì qǐ chū qù ba","english":"Get dressed! Let''s go out together","audioUrl":null},{"id":"b151a9f1-12d0-49d2-855c-c7d2099e2297","order":7,"chinese":"我们一起聊天吧","pinyin":"wǒ men yì qǐ liáo tiān ba","english":"Let''s chat together","audioUrl":null},{"id":"f1196616-3f57-4ddb-b7e4-38b0ae0499b0","order":8,"chinese":"你们都很饿, 对吧?","pinyin":"nǐ men dōu hěn è duì ba","english":"You''re all hungry, right?","audioUrl":null},{"id":"d7f5d87c-48fa-4618-b84d-59acd577c985","order":9,"chinese":"你们都很饿吧?","pinyin":"nǐ men dōu hěn è ba","english":"You''re all hungry, aren''t you?","audioUrl":null},{"id":"dfd4c2c3-1e0b-44d6-aedb-3dbfc6244b6b","order":10,"chinese":"他姓何, 对吧?","pinyin":"tā xìng hé duì ba","english":"His surname is He, right?","audioUrl":null},{"id":"6055f663-bd18-4d93-b742-53685662459e","order":11,"chinese":"我昨天得到四十三分! 不错吧?","pinyin":"wǒ zuó tiān dé dào sì shí sān fēn bú cuò ba","english":"I got forty-three points yesterday! Not bad, right?","audioUrl":null},{"id":"32b98480-3e25-442d-8807-2fe8528f3eab","order":12,"chinese":"选这个颜色吧! 这个更好看","pinyin":"xuǎn zhè ge yán sè ba zhè ge gèng hǎo kàn","english":"Go with this color! This one looks better","audioUrl":null},{"id":"6a36f175-f89f-400f-aa53-78ebb446db86","order":13,"chinese":"汤还是很热! 喝慢一点吧!","pinyin":"tāng hái shi hěn rè hē màn yì diǎn ba","english":"The soup is still hot! Drink it slowly!","audioUrl":null},{"id":"8fc7e3de-e72f-447f-9ef0-43a8f9463464","order":14,"chinese":"其他地方都没有这里那么有名吧!","pinyin":"qí tā dì fāng dōu méi yǒu zhè lǐ nà me yǒu míng ba","english":"No other place is as famous as here, right?","audioUrl":null}]}'::jsonb),
  (9, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"88538d39-b06d-4849-8ab1-cd67ea57d56b","order":0,"chinese":"我觉得他比你更帅","pinyin":"wǒ jué de tā bǐ nǐ gèng shuài","english":"I think he''s more handsome than you","audioUrl":null},{"id":"7277472b-36a7-4a30-8a91-cd58218dfd88","order":1,"chinese":"哇! 你开车的时候太帅了","pinyin":"wā nǐ kāi chē de shí hòu tài shuài le","english":"Wow! You look so cool when you drive","audioUrl":null},{"id":"738ea950-1044-4410-a81e-f19fb1a32e92","order":2,"chinese":"我发现坐地铁去上班比较方便","pinyin":"wǒ fā xiàn zuò dì tiě qù shàng bān bǐ jiào fāng biàn","english":"I''ve found that taking the subway to work is more convenient","audioUrl":null},{"id":"9e3db0a3-8901-4ac7-aa0b-156f271ee668","order":3,"chinese":"我发现这些问题都比较简单","pinyin":"wǒ fā xiàn zhè xiē wèn tí dōu bǐ jiào jiǎn dān","english":"I''ve found that these questions are relatively easy","audioUrl":null},{"id":"dfebf15b-1166-46bb-acbf-2b32629278f1","order":4,"chinese":"我发现这个女人比较漂亮一点","pinyin":"wǒ fā xiàn zhè ge nǚ ren bǐ jiào piào liang yì diǎn","english":"I''ve found this woman is a bit prettier","audioUrl":null},{"id":"cc5c2473-3fe0-401f-b9d4-8a3961fc9ab1","order":5,"chinese":"这幅画很漂亮, 多少钱?","pinyin":"zhè fú huà hěn piào liang duō shao qián","english":"This painting is beautiful — how much is it?","audioUrl":null},{"id":"a1918f50-ca67-4955-ac5d-4af5b9170d8a","order":6,"chinese":"我比较想知道为什么你还没结婚","pinyin":"wǒ bǐ jiào xiǎng zhī dào wèi shén me nǐ hái méi jié hūn","english":"I''d rather know why you''re still not married","audioUrl":null},{"id":"f23ffe61-c893-4c26-b9c8-22497b772d7f","order":7,"chinese":"比起以前, 中国的熊猫现在没有那么胖","pinyin":"bǐ qǐ yǐ qián zhōng guó de xióng māo xiàn zài méi yǒu nà me pàng","english":"Compared to before, China''s pandas aren''t as fat now","audioUrl":null},{"id":"f35c794a-9095-4453-9be4-3327469cb7d8","order":8,"chinese":"比起现在, 我觉得以前的才比较新鲜","pinyin":"bǐ qǐ xiàn zài wǒ jué de yǐ qián de cài bǐ jiào xīn xiān","english":"Compared to now, I think the food before was fresher","audioUrl":null},{"id":"718bd3e1-d5c7-4c76-a31a-db5a614559a7","order":9,"chinese":"比起以前, 我现在更害怕全球环境变化","pinyin":"bǐ qǐ yǐ qián wǒ xiàn zài gèng hài pà quán qiú huán jìng biàn huà","english":"Compared to before, I''m now more afraid of global environmental change","audioUrl":null},{"id":"0a6a534d-ee58-48f7-b224-dadc408411e6","order":10,"chinese":"奶奶比你漂亮但是你比她年轻","pinyin":"nǎi nai bǐ nǐ piào liang dàn shì nǐ bǐ tā nián qīng","english":"Grandma is prettier than you, but you''re younger than her","audioUrl":null},{"id":"b4cfdc41-95f8-4a29-acb6-7d6f8dae47f9","order":11,"chinese":"写汉语在黑板上比较清楚","pinyin":"xiě hàn yǔ zài hēi bǎn shàng bǐ jiào qīng chǔ","english":"Writing Chinese on the blackboard is clearer","audioUrl":null},{"id":"f33f7abf-3212-4e08-8b3c-b3a5c0237294","order":12,"chinese":"坐地铁上班应该比较方便吧","pinyin":"zuò dì tiě shàng bān yīng gāi bǐ jiào fāng biàn ba","english":"Taking the subway to work should be more convenient, right?","audioUrl":null}]}'::jsonb),
  (10, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"4d4a5a4c-3be9-4792-943d-2c72867f2803","order":0,"chinese":"我的铅笔又被人偷了","pinyin":"wǒ de qiān bǐ yòu bèi rén tōu le","english":"My pencil got stolen again","audioUrl":null},{"id":"ff9d9ccd-176f-49f8-ace2-78a1f0e49aa6","order":1,"chinese":"垃圾被我扔了","pinyin":"lā jī bèi wǒ rēng le","english":"The trash was thrown out by me","audioUrl":null},{"id":"80ef1dde-5498-4cdb-ad96-2cbfcb0ee9e1","order":2,"chinese":"我不想给他们发现","pinyin":"wǒ bù xiǎng gěi tā men fā xiàn","english":"I don''t want to be discovered by them","audioUrl":null},{"id":"723bc8eb-bf45-423d-bd75-084343a7434c","order":3,"chinese":"那枝筷子已经给服务员拿走了","pinyin":"nà zhī kuài zi yǐ jīng gěi fú wù yuán ná zǒu le","english":"That chopstick has already been taken away by the waiter","audioUrl":null},{"id":"f947bf55-d6b3-4ee2-988b-c4affa45b01d","order":4,"chinese":"那么好的机会被你浪费了","pinyin":"nà me hǎo de jī huì bèi nǐ làng fèi le","english":"Such a good opportunity was wasted by you","audioUrl":null},{"id":"e3bc680a-ca78-4359-8b50-a0a94c871cf2","order":5,"chinese":"不要浪费钱","pinyin":"bú yào làng fèi qián","english":"Don''t waste money","audioUrl":null},{"id":"b06667b6-5727-48df-a7e8-b45c459155ed","order":6,"chinese":"我今天浪费了很多时间","pinyin":"wǒ jīn tiān làng fèi le hěn duō shí jiān","english":"I wasted a lot of time today","audioUrl":null},{"id":"dfe83c40-8eb8-41ec-9a3e-c69c7d5b539d","order":7,"chinese":"快点吃饭! 不要浪费","pinyin":"kuài diǎn chī fàn bú yào làng fèi","english":"Hurry up and eat! Don''t waste it","audioUrl":null},{"id":"236c59a1-36b3-4b1a-9917-aec9e8bec9ff","order":8,"chinese":"所有钱都被你浪费了","pinyin":"suǒ yǒu qián dōu bèi nǐ làng fèi le","english":"All the money was wasted by you","audioUrl":null},{"id":"becb3269-18e2-4f3b-b862-379cb18c72db","order":9,"chinese":"如果你不准备好, 机会会被你浪费","pinyin":"rú guǒ nǐ bù zhǔn bèi hǎo jī huì huì bèi nǐ làng fèi","english":"If you don''t get ready, the opportunity will be wasted by you","audioUrl":null},{"id":"2ea79d55-214f-4252-941e-26145f9f40f6","order":10,"chinese":"全部垃圾都被我扔了","pinyin":"quán bù lā jī dōu bèi wǒ rēng le","english":"All the trash was thrown out by me","audioUrl":null}]}'::jsonb),
  (11, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"8ecce001-7291-46d2-bd22-a7546dc087cb","order":0,"chinese":"我今晚可能不回来","pinyin":"wǒ jīn wǎn kě néng bù huí lai","english":"I might not come back tonight","audioUrl":null},{"id":"6f02c33e-0f22-4217-99e8-580d802a57eb","order":1,"chinese":"如果我们小声一点, 我们可能不会被他发现","pinyin":"rú guǒ wǒ men xiǎo shēng yì diǎn wǒ men kě néng bú huì bèi tā fā xiàn","english":"If we''re a bit quieter, we might not get noticed by him","audioUrl":null},{"id":"1ac2f341-dd0a-42b5-9676-25b1e75c4b06","order":2,"chinese":"我突然要上厕所","pinyin":"wǒ tū rán yào shàng cè suǒ","english":"I suddenly need to use the toilet","audioUrl":null},{"id":"6e7ee137-7ba5-476f-8d95-c4c7357a4745","order":3,"chinese":"你要上厕所吗","pinyin":"nǐ yào shàng cè suǒ ma","english":"Do you need to use the toilet?","audioUrl":null},{"id":"037087c2-fe94-45a1-91d2-8e25827a1857","order":4,"chinese":"我本来是想照顾你的, 不过我现在不想了","pinyin":"wǒ běn lái shì xiǎng zhào gù nǐ de bú guò wǒ xiàn zài bù xiǎng le","english":"I originally wanted to take care of you, but now I don''t want to anymore","audioUrl":null},{"id":"8b3fefe7-b555-4e2e-b247-213b764ab588","order":5,"chinese":"我最近没有看新闻","pinyin":"wǒ zuì jìn méi yǒu kàn xīn wén","english":"I haven''t been watching the news lately","audioUrl":null},{"id":"674cbeeb-bd06-4e2a-981b-fd9195663ffb","order":6,"chinese":"好像我们最近都没有去运动","pinyin":"hǎo xiàng wǒ men zuì jìn dōu méi yǒu qù yùn dòng","english":"It seems we haven''t gone to exercise lately","audioUrl":null},{"id":"e992f341-1a2e-474d-a46f-697e9f839a87","order":7,"chinese":"我很想知道你的眼睛曾经见过什么","pinyin":"wǒ hěn xiǎng zhī dào nǐ de yǎn jing céng jīng jiàn guo shén me","english":"I really want to know what your eyes have seen before","audioUrl":null},{"id":"b017b303-61f8-4481-9d6f-75bf8c9a099f","order":8,"chinese":"几乎每个人的行李都要被检查","pinyin":"jī hū měi ge rén de xíng li dōu yào bèi jiǎn chá","english":"Almost everyone''s luggage has to be checked","audioUrl":null},{"id":"9009e3c9-3829-4d6b-a7d2-b0ee250ad507","order":9,"chinese":"我几乎笑到肚子痛","pinyin":"wǒ jī hū xiào dào dù zi tòng","english":"I almost laughed until my stomach hurt","audioUrl":null},{"id":"88a092b0-66a9-4dfa-900e-d8859fec378d","order":10,"chinese":"他一个人几乎吃了整个蛋糕, 应该吃饱了吧","pinyin":"tā yí gè rén jī hū chī le zhěng ge dàn gāo yīng gāi chī bǎo le ba","english":"He almost ate the whole cake by himself — he must be full, right?","audioUrl":null},{"id":"9e850c22-0b7d-4555-af8f-d9e153d50dbb","order":11,"chinese":"整个国际社会都同意","pinyin":"zhěng gè guó jì shè huì dōu tóng yì","english":"The entire international community agrees","audioUrl":null},{"id":"640ba300-60fb-4564-be16-7b288999ee44","order":12,"chinese":"我本来不相信你, 但是现在我信了","pinyin":"wǒ běn lái bù xiāng xìn nǐ dàn shì xiàn zài wǒ xìn le","english":"I didn''t believe you at first, but now I do","audioUrl":null},{"id":"7845d4d0-4a0e-4899-bfd7-6e16d3e70f36","order":13,"chinese":"跳这么高是不可能的","pinyin":"tiào zhè me gāo shì bù kě néng de","english":"Jumping this high is impossible","audioUrl":null},{"id":"6d28bab2-aca6-4da4-b264-50e97be9f141","order":14,"chinese":"你为什么要突然出来? 我还没化妆","pinyin":"nǐ wèi shén me yào tū rán chū lái wǒ hái méi huà zhuāng","english":"Why did you come out all of a sudden? I haven''t put on makeup yet","audioUrl":null}]}'::jsonb),
  (12, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"d6cb9caf-2017-47d1-9063-4559d8bdd6fb","order":0,"chinese":"然后我们要去买最便宜的饮料","pinyin":"rán hòu wǒ men yào qù mǎi zuì pián yí de yǐn liào","english":"Then we''re going to buy the cheapest drinks","audioUrl":null},{"id":"6e761f12-0440-4a8f-ad73-55059d747b60","order":1,"chinese":"先打开冰箱, 然后帮我那一些吃的","pinyin":"xiān dǎ kāi bīng xiāng rán hòu bāng wǒ ná yī xiē chī de","english":"Open the fridge first, then get me some food","audioUrl":null},{"id":"3171f7d3-2178-44d4-a7ac-40a926d84c5e","order":2,"chinese":"然后医生和我说, 生病了一定要吃药","pinyin":"rán hòu yī shēng hé wǒ shuō shēng bìng le yí dìng yào chī yào","english":"Then the doctor told me: when you''re sick, you must take medicine","audioUrl":null},{"id":"4d65f76c-ba6e-4d1a-9982-a3f32764b6c8","order":3,"chinese":"马上上去楼上, 然后帮我拿我的眼镜","pinyin":"mǎ shàng shàng qù lóu shàng rán hòu bāng wǒ ná wǒ de yǎn jīng","english":"Go upstairs right now, then get me my glasses","audioUrl":null},{"id":"ee2bd976-57ad-49db-83d9-a9f1807137bf","order":4,"chinese":"你们原来住在东边, 但是最近搬到西边","pinyin":"nǐ men yuán lái zhù zài dōng bian dàn shì zuì jìn bān dào xī bian","english":"You used to live on the east side, but recently moved to the west side","audioUrl":null},{"id":"f8dff60e-2220-44f9-a989-31cff5278a66","order":5,"chinese":"原来他没有发烧他只是感冒","pinyin":"yuán lái tā méi yǒu fā shāo tā zhǐ shì gǎn mào","english":"It turns out he didn''t have a fever, he just had a cold","audioUrl":null},{"id":"d4ca2db9-e082-4c8e-a882-96f3fa32c0ef","order":6,"chinese":"我猜两个答案应该都一样","pinyin":"wǒ cāi liǎng gè dá àn yīng gāi dōu yí yàng","english":"I''m guessing both answers should be the same","audioUrl":null},{"id":"f48b528b-b8c1-47b6-9bd9-049b4a1fe0f9","order":7,"chinese":"反正我肚子饿, 你弄点吃的吧","pinyin":"fǎn zhèng wǒ dù zi è nǐ nòng diǎn chī de ba","english":"I''m hungry anyway, so make something to eat","audioUrl":null},{"id":"ab2d5e6a-75c6-4257-9e67-6248ad9e049d","order":8,"chinese":"没关系, 反正我现在不想要了, 真的","pinyin":"méi guān xì fǎn zhèng wǒ xiàn zài bù xiǎng yào le zhēn de","english":"It''s okay, I don''t want it anymore anyway, really","audioUrl":null},{"id":"c5e382e3-b28d-48e6-97b2-2f166bdcfe91","order":9,"chinese":"先猜我有多少钱, 然后选餐厅","pinyin":"xiān cāi wǒ yǒu duō shǎo qián rán hòu xuǎn cān tīng","english":"First guess how much money I have, then pick a restaurant","audioUrl":null},{"id":"3c2436a5-130f-4852-b638-8774dc3adb6e","order":10,"chinese":"马上拿一张信用卡出来! 然后买这条裤子!","pinyin":"mǎ shàng ná yī zhāng xìn yòng kǎ chū lái rán hòu mǎi zhè tiáo kù zi","english":"Take out a credit card right now! Then buy these pants!","audioUrl":null},{"id":"d0b47d05-1be7-4647-bd2f-ab2d763e2243","order":11,"chinese":"原来是你投了老爷的钱","pinyin":"yuán lái shì nǐ tōu le lǎo yé de qián","english":"So it was you who stole the master''s money","audioUrl":null}]}'::jsonb),
  (13, '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"c7ead54d-82b6-44a6-ae96-2b5f87e1eb5d","order":0,"chinese":"你最近怎么样?","pinyin":"nǐ zuì jìn zěn me yàng","english":"How have you been lately?","audioUrl":null},{"id":"645d0aa0-1b31-4d19-9fba-58da6e7d90c2","order":1,"chinese":"儿子过来教爸爸怎么用电脑","pinyin":"ér zi guò lai jiāo bà ba zěn me yòng diàn nǎo","english":"The son comes over to teach his dad how to use the computer","audioUrl":null},{"id":"e291bdb3-6cff-403c-a275-24a56aea76cf","order":2,"chinese":"我特别喜欢中国文化, 你呢?","pinyin":"wǒ tè bié xǐ huan zhōng guó wén huà nǐ ne","english":"I especially love Chinese culture — how about you?","audioUrl":null},{"id":"ea6ae0c5-5622-488f-bdb6-37e423091e35","order":3,"chinese":"这个用中文怎么说? 那个呢?","pinyin":"zhè ge yòng zhōng wén zěn me shuō nà ge ne","english":"How do you say this in Chinese? And that one?","audioUrl":null},{"id":"c12387fc-3ef9-4ebe-8b07-86805be6e2a4","order":4,"chinese":"我已经改变了我的答案. 你呢?","pinyin":"wǒ yǐ jīng gǎi biàn le wǒ de dá àn nǐ ne","english":"I''ve already changed my answer. How about you?","audioUrl":null},{"id":"568d0eba-9b08-43cb-b3a7-312fdfa48e7f","order":5,"chinese":"爸爸那时候十九岁就已经找到妻子了","pinyin":"bà ba nà shí hou shí jiǔ suì jiù yǐ jīng zhǎo dào qī zi le","english":"Back then, at nineteen, Dad had already found a wife","audioUrl":null},{"id":"d74c4f11-640a-4565-a196-2c991c6cc962","order":6,"chinese":"你什么时候有空? 我想和你一起听音乐","pinyin":"nǐ shén me shí hou yǒu kòng wǒ xiǎng hé nǐ yì qǐ tīng yīn yuè","english":"When are you free? I want to listen to music with you","audioUrl":null},{"id":"ec66fe2a-078a-47ef-921a-34dd6e0d37cd","order":7,"chinese":"你到底想不想解决这个问题","pinyin":"nǐ dào dǐ xiǎng bù xiǎng jiě jué zhè ge wèn tí","english":"Do you actually want to solve this problem or not?","audioUrl":null},{"id":"d3eaa70d-56d3-4548-903f-4b3d4405fe1d","order":8,"chinese":"你不可能知道到底正在发生什么事情","pinyin":"nǐ bù kě néng zhī dào dào dǐ zhèng zài fā shēng shén me shì qíng","english":"There''s no way you could know what''s actually happening","audioUrl":null},{"id":"4c21f265-4684-4569-8004-31f553840939","order":9,"chinese":"我在唱歌","pinyin":"wǒ zài chàng gē","english":"I''m singing","audioUrl":null},{"id":"d22baa4b-4fd1-4105-9dbe-a1575f6487eb","order":10,"chinese":"我正在唱歌","pinyin":"wǒ zhèng zài chàng gē","english":"I''m singing right now","audioUrl":null},{"id":"5a5f6f00-946c-4d61-9f6e-bbdd45563428","order":11,"chinese":"你觉得他写的怎么样?","pinyin":"nǐ jué de tā xiě de zěn me yàng","english":"What do you think of what he wrote?","audioUrl":null},{"id":"ba323390-17a4-4ead-8985-dc2f8ed1f798","order":12,"chinese":"我很喜欢这两位歌手! 你呢?","pinyin":"wǒ hěn xǐ huan zhè liǎng wèi gē shǒu nǐ ne","english":"I really like these two singers! How about you?","audioUrl":null},{"id":"20dd138c-cbab-4318-93c7-381bce325c5b","order":13,"chinese":"明天怎么样? 有没有空?","pinyin":"míng tiān zěn me yàng yǒu méi yǒu kòng","english":"How about tomorrow? Are you free?","audioUrl":null},{"id":"eff91a87-5bf2-4233-8f8a-1e87825ad0de","order":14,"chinese":"明天怎么样? 有空吗?","pinyin":"míng tiān zěn me yàng yǒu kòng ma","english":"How about tomorrow? Are you free?","audioUrl":null}]}'::jsonb)
) AS v(n, content)
WHERE l."lesson_type" = 'audio'
  AND l."deleted_at" IS NULL
  AND l."title" ILIKE '%intensive listening%'
  AND (substring(lower(l."title") from 'intermediate[^0-9]*([0-9]+)'))::int = v.n
  AND l."module_id" IN (
    SELECT m."id"
    FROM "course_library_modules" m
    JOIN "course_library_courses" c ON c."id" = m."course_id"
    WHERE m."deleted_at" IS NULL
      AND c."deleted_at" IS NULL
      AND lower(trim(c."title")) = 'the canto to mando blueprint - intermediate'
  );
